if (ctx->LeftParen()) {
    auto funcType = make<FunctionType>();
    funcType->sub = sub;

    if (auto p = ctx->parameterTypeList()) {
      if (auto paramList = p->parameterList()) {
        for (auto&& param : paramList->parameterDeclaration()) {
          auto specs = self(param->declarationSpecifiers());
          auto [texp, name] = self(param->declarator(), nullptr);
          auto paramDecl = make<VarDecl>();
          auto type = make<Type>();
          paramDecl->type = type;
          type->spec = specs.first;
          type->qual = specs.second;
          type->texp = texp;
          paramDecl->name = std::move(name);
          funcType->params.push_back(paramDecl);
        }
      }
    }

    return self(ctx->directDeclarator(), funcType);
  }

